 8→/**
 9→ * A representation of a leaf node for generating PyIntObjs.
10→ */
11→public class PyIntNode extends APyNode<PyIntObj> {
12→
13→    /**
14→     * Generates all valid PyIntObjs within the exhaustive domain.
15→     *
16→     * @return a set of PyIntObjs comprising the exhaustive domain
17→     */
18→    @Override
19→    public Set<PyIntObj> genExVals() {
20→        Set<PyIntObj> vals = new HashSet<>();
21→        for (Number value : this.exDomain) {
22→            vals.add(new PyIntObj(value.intValue()));
23→        }
24→        return vals;
25→    }
26→
27→    /**
28→     * Generates a single valid PyIntObj within the random domain.
29→     *
30→     * @return a single PyIntObj selected from the random domain
31→     */
32→    @Override
33→    public PyIntObj genRandVal() {
34→        return new PyIntObj(this.ranDomainChoice().intValue());
35→    }
36→}

